head.script:
scwin.onpageload = function () {
    scwin.loadFolders();
    window.setTimeout(function () { scwin._setEditable(false); }, 50);
};

scwin.callApi = function (url, callback) {
    var xhr = new XMLHttpRequest();
    xhr.open("GET", url, true);
    xhr.onreadystatechange = function () {
        if (xhr.readyState === 4) {
            if (xhr.status >= 200 && xhr.status < 300) {
                callback(JSON.parse(xhr.responseText || "{}"));
            }
        }
    };
    xhr.send();
};
scwin._currentFolderId = 1;

scwin._buildFolderRows = function (folders) {
    var childrenMap = {};
    var allIds = {};
    for (var i = 0; i < folders.length; i++) { allIds[folders[i].folderId] = true; }
    for (var j = 0; j < folders.length; j++) {
        var pid = folders[j].parentFolderId || 0;
        if (!childrenMap[pid]) { childrenMap[pid] = []; }
        childrenMap[pid].push(folders[j]);
    }
    var roots = [];
    for (var k = 0; k < folders.length; k++) {
        var f = folders[k];
        if (!f.parentFolderId || !allIds[f.parentFolderId]) { roots.push(f); }
    }
    var result = [];
    var visit = function (node, depth) {
        result.push({ FOLDER_ID: String(node.folderId), FOLDER_NM: node.folderNm || "", DEPTH: String(depth) });
        var children = childrenMap[node.folderId] || [];
        for (var x = 0; x < children.length; x++) { visit(children[x], depth + 1); }
    };
    for (var y = 0; y < roots.length; y++) { visit(roots[y], 1); }
    return result;
};


scwin.loadFolders = function () {
    scwin.callApi("/api/dam/folders", function (folders) {
       if (!folders || folders.length === 0) {
            dlFolder.setJSON([]);
            dlVersion.setJSON([]);
            scwin._applyDetail(-1);
            return;
        }

        dlFolder.setJSON(scwin._buildFolderRows(folders));
        scwin._loadFirstFolderWithAssets(folders, 0);

        try {
            var tv = $p.getComponentById("trvVersionFolder");
            if (tv && typeof tv.expandAll === "function") { tv.expandAll(); }
        } catch (e) {}
    });
};
scwin.trvVersionFolder_onclick = function () {
    var nodeValue = trvVersionFolder.getSelectedValue();
    var fid = parseInt(nodeValue, 10);
    if (isNaN(fid) || fid <= 0 || fid === scwin._currentFolderId) { return; }
    scwin._currentFolderId = fid;
    scwin.loadAssets(fid);
};

scwin._loadFirstFolderWithAssets = function (folders, index) {
    if (!folders || index >= folders.length) {
        dlVersion.setJSON([]);
        scwin._applyDetail(-1);
        return;
    }
    var folder = folders[index];
    var folderId = folder.folderId || folder.FOLDER_ID;
    scwin.callApi("/api/dam/assets?folderId=" + folderId, function (list) {
        if (list && list.length > 0) {
        scwin._currentFolderId = parseInt(folderId, 10) || 1;
            scwin.loadAssets(folderId);
        } else {
            scwin._loadFirstFolderWithAssets(folders, index + 1);
        }
    });
};

scwin._formatFileSize = function (bytes) {
    var n = parseFloat(bytes || 0);
    if (!n || n <= 0) { return "0 B"; }
    var kb = 1024;
    var mb = kb * 1024;
    var gb = mb * 1024;
    if (n >= gb) { return (n / gb).toFixed(2) + " GB"; }
    if (n >= mb) { return (n / mb).toFixed(2) + " MB"; }
    if (n >= kb) { return (n / kb).toFixed(2) + " KB"; }
    return n + " B";
};

scwin.loadAssets = function (folderId) {
    scwin.callApi("/api/dam/assets?folderId=" + folderId, function (list) {
        var rows = [];
        for (var i = 0; i < (list || []).length; i++) {
            var item = list[i];
            rows.push({
                "CHK": "",
                "ASSET_ID": item.assetId,
                "ICON": item.fileExt ? item.fileExt.toUpperCase() : (item.fileType || ""),
                "FILE_NM": item.fileNm || "",
                "FILE_TYPE": item.fileType || "",
                "FILE_SIZE": scwin._formatFileSize(item.fileSize),
                "STATUS": item.status || "Draft",
                "PREVIEW_URL": item.previewUrl || "/cm/dam/images/preview/document.svg",
                "TAGS": item.tags || "",
                "CREATOR": item.ownerNm || "",
                "RESOLUTION": item.resolution || "-",
                "UPLOAD_DT": item.uploadDt || ""
            });
        }
        dlVersion.setJSON(rows);
        if (rows.length > 0) {
            scwin.loadAssetDetail(rows[0].ASSET_ID);
        } else {
            scwin._applyDetail(-1);
        }
    });
};

scwin.loadAssetDetail = function (assetId) {
    scwin.callApi("/api/dam/assets/" + assetId, function (response) {
        var asset = response.asset || {};
        var latestVersion = (response.versions && response.versions.length > 0) ? response.versions[0] : {};

        scwin._setVal("inp_versionFileName", asset.fileNm || "");
        scwin._setVal("sel_versionAssetType", asset.tags || "");
        scwin._setVal("sel_versionStatus", asset.status || "Draft");
        scwin._setVal("inp_versionCreator", asset.ownerNm || latestVersion.ownerNm || "");
        scwin._setVal("inp_versionResolution", asset.resolution || "-");
        scwin._setVal("inp_versionUploaded", asset.uploadDt || latestVersion.uploadDt || "");

        try {
            var img = $p.getComponentById("img_versionPreview");
            if (img && typeof img.setSrc === "function") {
                img.setSrc(asset.previewUrl || latestVersion.previewUrl || "/cm/dam/images/preview/document.svg");
            }
        } catch (e) {}
    });
};

scwin.grdVersion_onrowindexchange = function (gridObj, oldRowIndex, newRowIndex) {
    var row = dlVersion.getRowJSON(newRowIndex);
    if (row && row.ASSET_ID) {
        scwin.loadAssetDetail(row.ASSET_ID);
    } else {
        scwin._applyDetail(newRowIndex);
    }
};

scwin._setVal = function (id, val) {
    try {
        var c = $p.getComponentById(id);
        if (c && typeof c.setValue === "function") { c.setValue(val); }
    } catch (e) {}
};

scwin._applyDetail = function (rowIndex) {
    var row = dlVersion.getRowJSON(rowIndex);
    if (!row) {
        scwin._setVal("inp_versionFileName", "");
        scwin._setVal("sel_versionAssetType", "");
        scwin._setVal("sel_versionStatus", "Draft");
        scwin._setVal("inp_versionCreator", "");
        scwin._setVal("inp_versionResolution", "");
        scwin._setVal("inp_versionUploaded", "");
        return;
    }

    try {
        var img = $p.getComponentById("img_versionPreview");
        if (img && typeof img.setSrc === "function") {
            img.setSrc(row.PREVIEW_URL || "/cm/dam/images/preview/document.svg");
        }
    } catch (e) {}

    scwin._setVal("inp_versionFileName", row.FILE_NM || "");
    scwin._setVal("sel_versionAssetType", row.TAGS || "");
    scwin._setVal("sel_versionStatus", row.STATUS || "");
    scwin._setVal("inp_versionCreator", row.CREATOR || "");
    scwin._setVal("inp_versionResolution", row.RESOLUTION || "");
    scwin._setVal("inp_versionUploaded", row.UPLOAD_DT || "");
};

scwin.btn_versionDownload_onclick = function () { /* mock */ };
scwin._editMode = false;
scwin._currentRow = -1;

scwin._setEditable = function (editable) {
    try { inp_versionFileName.setReadOnly(!editable); } catch (e) {}
    try {
        var statusEl = document.getElementById("sel_versionStatus");
        if (statusEl) {
            statusEl.style.pointerEvents = editable ? "auto" : "none";
            statusEl.style.opacity = editable ? "1" : "0.9";
        }
    } catch (e) {}
    try {
        var tagsEl = document.getElementById("sel_versionAssetType");
        if (tagsEl) {
            tagsEl.style.pointerEvents = editable ? "auto" : "none";
            tagsEl.style.opacity = editable ? "1" : "0.9";
        }
    } catch (e) {}
    try { btn_versionEdit.setLabel(editable ? "Save Changes" : "Edit Metadata"); } catch (e) {}
};

scwin._persistMetadata = function (rowIndex) {
    var row = dlVersion.getRowJSON(rowIndex);
    if (!row || !row.ASSET_ID) { return; }

    var fileNm = inp_versionFileName.getValue() || "";
    var tags = sel_versionAssetType.getValue() || "";
    var status = sel_versionStatus.getValue() || "Draft";

    row.FILE_NM = fileNm;
    row.TAGS = tags;
    row.STATUS = status;
    dlVersion.setCellData(rowIndex, "FILE_NM", fileNm);
    dlVersion.setCellData(rowIndex, "TAGS", tags);
    dlVersion.setCellData(rowIndex, "STATUS", status);

    fetch("/api/dam/assets/" + row.ASSET_ID, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ fileNm: fileNm, tags: tags, status: status })
    }).then(function (r) { return r.json(); })
      .then(function () { scwin.loadAssetDetail(row.ASSET_ID); }, function (e) {
          console.warn("[Version] save metadata failed", e);
      });
};

scwin.btn_versionEdit_onclick = function () {
    var idx = grdVersion.getFocusedRowIndex ? grdVersion.getFocusedRowIndex() : -1;
    if (idx < 0) { return; }
    scwin._currentRow = idx;

    if (!scwin._editMode) {
        scwin._editMode = true;
        scwin._setEditable(true);
        return;
    }

    scwin._persistMetadata(idx);
    scwin._editMode = false;
    scwin._setEditable(false);
};
